<template>
    <div class="md:w-7/12 w-full h-full flex flex-col gap-2" >
        <div class="h-[80%] w-full rounded-lg shadow-2xl px-2 pt-2">
            <div class="flex gap-4 h-[5%]">
               <Customer v-model:customer="invoiceStore.invoiceCustomer" />
                <Button
                    class="w-1/12"
                    @click="loadComponent('CustomerForm');"
                    :variant="'solid'"
                    :ref_for="true"
                    theme="gray"
                    size="sm"
                    label="Button"
                    :loading="false"
                    :loadingText="null"
                    :disabled="false"
                    :link="null"
                >
                    <FeatherIcon
                    class="w-4 cursor-pointer"
                    name="plus"
                    @click="loadComponent('CustomerForm');"
                    />
                </Button>
            </div>
            <div class="py-2  h-[93%] overflow-y-scroll scrollbar-hide flex flex-col items-center w-full ">
                <div class="mb-2 w-full flex flex-col items-center">
                    <div class="flex bg-gray-200 w-full py-2 px-3 justify-between rounded text-center ">
                        <div class="w-[18.4%]">
                            Item Code
                        </div>
                        <div  class="w-[18.4%]">
                            QTY
                        </div>
                        <div  class="w-[18.4%]">
                            UOM
                        </div>
                        <div  class="w-[18.4%]">
                            Rate
                        </div>
                        <div  class="w-[18.4%]">
                            Amount
                        </div>
                        <div class="w-[8%]">
                            Remove
                        </div>
                    </div>
                </div>
                <div v-for="(item, key) in invoiceStore.items" :key="item.custom_id" class="flex flex-col justify-between mb-2 w-full ">
                    <Item :items="item" :index="key"  />                   
                </div>
            </div>
        </div>

        <div class="h-[20%] flex shadow-2xl rounded">
            <div class=" w-[60%] grid grid-cols-2 gap-4 p-4 h-full">
                <FormControl
                    :type="'number'"
                    :ref_for="true"
                    size="sm"
                    variant="subtle"
                    placeholder="0.00"
                    :disabled="true"
                    label="Total Qty"
                    v-model="invoiceStore.invoice.total_qty"
                />
                <FormControl
                    v-if="store.posProfileData?.custom_use_percentage_discount"
                    :type="'number'"
                    :ref_for="true"
                    size="sm"
                    variant="subtle"
                    placeholder="0.00"
                    :disabled="!store.posProfileData?.allow_discount_change"
                    label="Additional Discount (%)"
                    v-model="invoiceStore.invoice._additional_discount_percentage"
                />
                <FormControl
                    v-else
                    :type="'number'"
                    :ref_for="true"
                    size="sm"
                    variant="subtle"
                    placeholder="0.00"
                    :disabled="!store.posProfileData?.allow_discount_change"
                    :label="`Additional Discount (${store.posProfileData?.currency})`"
                    v-model="invoiceStore.invoice._discount_amount"
                    :value="Number(invoiceStore.invoice._discount_amount).toFixed(2)"
                    />
                <FormControl
                    :type="'number'"
                    :ref_for="true"
                    size="sm"
                    variant="subtle"
                    placeholder="0.00"
                    :disabled="true"
                    label="Net Total"
                    :class="''"
                    :value="Number(invoiceStore.invoice.net_total).toFixed(2)"
                    v-model="invoiceStore.invoice.net_total"
                />
                <FormControl
                    :type="'number'"
                    :ref_for="true"
                    size="sm"
                    variant="subtle"
                    placeholder="0.00"
                    :disabled="true"
                    label="Total"
                    :class="''"
                    :value="Number(invoiceStore.invoice.grand_total).toFixed(2)"
                    v-model="invoiceStore.invoice.grand_total"
                />

            </div>
            <div class=" w-[40%] h-full grid grid-cols-2 gap-2 p-4">
                <Button
                    :ref_for="true"
                    label="Button"
                    :loading="false"
                    :loadingText="null"
                    :disabled="false"
                    :link="null"
                    theme="blue"
                    @click="loadComponent('Held')"
                >
                    HELD
                </Button>
                <Button
                    :ref_for="true"
                    label="Button"
                    :loading="false"
                    :loadingText="null"
                    :disabled="false"
                    :link="null"
                    theme="red"
                    @click="loadComponent('Return')"            
                >
                    RETURN
                </Button>
                <Button
                    v-if="permissionStore.salesInvoiceCanCreate"
                    :ref_for="true"
                    label="Button"
                    :loading="false"
                    :loadingText="null"
                    :disabled="false"
                    :link="null"
                    :variant="'solid'"
                    theme="gray"
                    @click="sales_invoice.fetch({ action:'Save', status:'save_new' })"
                >
                    SAVE/NEW
                </Button>
                <Button
                    v-if="permissionStore.salesInvoiceCanSubmit"
                    :ref_for="true"
                    label="Button"
                    :loading="false"
                    :loadingText="null"
                    :disabled="false"
                    :link="null"
                    theme="green"
                    @click="sales_invoice.fetch({ action:'Save', status:'pay' })"
                >
                    PAY
                </Button>
                <Button
                    v-if="permissionStore.salesInvoiceCanPrint && permissionStore.salesInvoiceCanCreate"
                    :ref_for="true"
                    label="Button"
                    :loading="false"
                    :loadingText="null"
                    :disabled="false"
                    :link="null"
                    :variant="'solid'"
                    theme="gray"
                    @click="sales_invoice.fetch({ action:'Save', status:'print' })"
                >
                SAVE & PRINT
                </Button>
            </div>
        </div>
    </div>
</template>

<script setup>
import Customer from '@/components/Customer.vue';
import { Button, FeatherIcon, FormControl, createResource, debounce} from 'frappe-ui';
import { inject , watch } from 'vue';
import { createToast, showToast } from '@/utils';
import { usePosProfileStore } from '@/stores/posProfile';
import { usePermissionStore } from '@/stores/permission';
import { useInvoiceStore } from '@/stores/pos';
import emitter from '@/utils/emitter'; 
import Item from '@/components/Item.vue';

const store = usePosProfileStore();
const permissionStore = usePermissionStore();
const invoiceStore = useInvoiceStore()
const { loadComponent } = inject('dynamicComponent');
const baseurl = createResource({url: 'ant_pos.ant_pos.utils.get_domain_url'});
let status = '';
let sales_invoice = createResource({
    url: 'frappe.desk.form.save.savedocs',
    makeParams(params) {
        invoiceStore.items.forEach((item) => {                
            if (item.has_serial_no && item.selected_serial_no.length !== item.qty) {
                createToast({
                    title: 'error',
                    message: 'Serial number is required',
                    iconClasses: 'bg-surface-red-5 text-ink-white rounded-md p-px',
                    position: 'top-center',
                    timeout: 5,
                });
            }
        });
        status = params.status
        return {
            doc: JSON.stringify({
                ...invoiceStore.invoice,
                doctype: 'Sales Invoice',
                is_pos: invoiceStore.invoice.is_return ? invoiceStore.invoice.is_pos : 1,
                pos_profile: store.posProfileData.name,
                company: store.posProfileData.company,
                conversion_rate: 1,
                selling_price_list: store.posProfileData.selling_price_list,
                items: invoiceStore.items,
                customer: invoiceStore.invoiceCustomer.name,
                update_stock: 1,
                additional_discount_percentage: Number(invoiceStore.invoice._additional_discount_percentage) || 0,
                discount_amount: Number(invoiceStore.invoice._discount_amount) || 0,
                base_total: invoiceStore.invoice.base_total && invoiceStore.invoice.base_total,
                custom_ant_opening: store.openingShift.name,
                apply_discount_on: store.posProfileData.apply_discount_on,
                payments:getPayments(),
                advances:getAdvances()
            }),
            action:params.action,
        };
    },
    async onSuccess (data) {
        if ( status == 'pay'){
            invoiceStore.invoice = { ...data.docs[0] ,docstatus:1 }
            return

        }else if (status == 'print'){
            await baseurl.fetch()
            window.open(
                `${baseurl.data}/printview?doctype=Sales+Invoice&name=${
                    data.docs[0].name
                }&format=${encodeURIComponent(store.posProfileData.print_format)}&trigger_print=1&no_letterhead=${store.posProfileData.letter_head ? 1 :0 }
                &letterhead=${store.posProfileData.letter_head}`,
                "_blank"
            );
        }
        showToast('success', 'Sales Invoice Drafted Successfully')
        emitter.emit('remove_invoice', true);
    },
    onError(error) {
        createToast({
            title: 'error',
            message: Array.isArray(error?.messages) ? error.messages[0] : error?.messages || error || 'An error occurred',
            icon: 'x-circle',
            iconClasses: 'bg-surface-red-5 text-ink-white rounded-md p-px',
            position: 'top-center',
            timeout: 5,
        });
    },
});
   
const getPayments = () => {
    const total = invoiceStore.invoice.is_return ? -Math.abs(invoiceStore.invoice.rounded_total) : invoiceStore.invoice.rounded_total;
    const payments = invoiceStore.invoice.payments.map(p => {
        const amount = p.default ? total : 0;
        return {
            ...p,
            amount,
            base_amount: amount
        };
    });
    return payments;
};

const getAdvances = () => {
    if (!invoiceStore.invoice.advances) return [];
    if (invoiceStore.invoice.is_return) return [];
    return invoiceStore.invoice.advances;
};

const calculateDiscount = () => {
    let amount = store.posProfileData?.apply_discount_on === 'Grand Total' ? invoiceStore.invoice.base_grand_total : invoiceStore.invoice.base_net_total;

    if (store.posProfileData?.custom_use_percentage_discount) {
        invoiceStore.invoice._discount_amount= (( amount + invoiceStore.invoice?.discount_amount ) * 100) / invoiceStore.invoice._additional_discount_percentage;
    } else {
        invoiceStore.invoice._additional_discount_percentage = invoiceStore.invoice._discount_amount * (100 / ( amount + invoiceStore.invoice?.discount_amount ));
    }
};

const debouncedDiscount = debounce(calculateDiscount, 300);

watch(
    () => invoiceStore.invoice._discount_amount,
    (newVal,oldVal) => {
        if (!store.posProfileData?.custom_use_percentage_discount && newVal !== oldVal) {
            calculateDiscount();
            emitter.emit('calctotal');
        }
    },
    { flush: 'post' }
);

watch(
  [() => invoiceStore.invoice.grand_total, () => invoiceStore.invoice.net_total],
  (newValues, oldValues) => {
    const [newGrand, newNet] = newValues;
    const [oldGrand, oldNet] = oldValues;

    if (newGrand !== oldGrand || newNet !== oldNet) {
      debouncedDiscount();
    }
  }
);


</script>
